if (!isOwner()) {
  require(_isRole(role), "Caller does not have a required role.");
  require(!_isPaused(role), "Role in question is currently paused.");
}

require(
  (address(bytes20(salt)) == msg.sender) ||
  (bytes20(salt) == bytes20(0)),
  "Invalid salt - first 20 bytes of the salt must match calling address."
);

require(
  _keys[uint160(msg.sender)] == KeyType.Admin ||
  _keys[uint160(msg.sender)] == KeyType.Dual,
  "Only Admin or Dual key holders can call this function."
);

require(
  keyTypes.length == 1 && keyTypes[0] == uint8(3),
  "Must supply exactly one Dual keyType (3) in V1."
);

if (_setFullApproval(AssetType.DAI)) {
  // Get the current Dai balance on this contract.
  uint256 daiBalance = _DAI.balanceOf(address(this));

  // Try to deposit the full Dai balance on Compound.
  _depositOnCompound(AssetType.DAI, daiBalance);
}

if (data.length == 32) {
  digest = abi.decode(data, (bytes32));
} else {
  require(data.length >= 64, _revertReason(30));
  (digest, context) = abi.decode(data, (bytes32, bytes));
}

assembly {
  r := mload(add(signaturesInMemory, 0x20))
  s := mload(add(signaturesInMemory, 0x40))
  v := byte(0, mload(add(signaturesInMemory, 0x60)))
}

assembly {
  r := mload(add(signaturesInMemory, 0x61))
  s := mload(add(signaturesInMemory, 0x81))
  v := byte(0, mload(add(signaturesInMemory, 0xa1)))
}

if (callerAllowance != uint256(-1)) {
  require(callerAllowance >= amount, "Insufficient allowance.");
  _approve(sender, msg.sender, callerAllowance - amount); // overflow safe.
}

assembly {
  r := mload(add(signature, 0x20))
  s := mload(add(signature, 0x40))
  v := byte(0, mload(add(signature, 0x60)))
}

struct ARBACStorage {
    mapping(string => mapping(bool => mapping(string => DynamicSet.StringSet))) rolePermissions;
    mapping(string => mapping(bool => DynamicSet.StringSet)) roleResources;
    mapping(address => DynamicSet.StringSet) userRoles;
}

for (uint256 i = 0; i < permissionsToAdd_.length; ++i) {
    _addPermissionsToRole(
        role_,
        permissionsToAdd_[i].resource,
        permissionsToAdd_[i].permissions,
        allowed_
    );
}

for (uint256 i = 0; i < permissionsToRemove_.length; ++i) {
    _removePermissionsFromRole(
        role_,
        permissionsToRemove_[i].resource,
        permissionsToRemove_[i].permissions,
        allowed_
    );
}

mapping(string => DynamicSet.StringSet) storage _allowedPermissions = $.rolePermissions[
            role_
        ][true];

mapping(string => DynamicSet.StringSet) storage _disallowedPermissions = $.rolePermissions[
            role_
        ][false];

for (uint256 i = 0; i < allowed_.length; ++i) {
    allowed_[i].resource = _allowedResources.at(i);
    allowed_[i].permissions = _allowedPermissions[allowed_[i].resource].values();
}

DynamicSet.StringSet storage _permissions = $.rolePermissions[role_][allowed_][
    resourceToAdd_
];

DynamicSet.StringSet storage _permissions = $.rolePermissions[role_][allowed_][
    resourceToRemove_
];

if (
    msg.sender != address(this) &&
    msg.sender != trustedExecutor() &&
    msg.sender != entryPoint()
) {
    revert InvalidExecutor(msg.sender);
}

assembly ("memory-safe") {
    let factor := shl(7, gt(x, 0xFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFF))
    x := shr(factor, x)
    result := or(result, factor)
}

assembly ("memory-safe") {
    let factor := shl(6, gt(x, 0xFFFFFFFFFFFFFFFF))
    x := shr(factor, x)
    result := or(result, factor)
}

assembly ("memory-safe") {
    let factor := shl(5, gt(x, 0xFFFFFFFF))
    x := shr(factor, x)
    result := or(result, factor)
}

assembly ("memory-safe") {
    let factor := shl(4, gt(x, 0xFFFF))
    x := shr(factor, x)
    result := or(result, factor)
}

assembly ("memory-safe") {
    let factor := shl(3, gt(x, 0xFF))
    x := shr(factor, x)
    result := or(result, factor)
}

assembly ("memory-safe") {
    let factor := shl(2, gt(x, 0xF))
    x := shr(factor, x)
    result := or(result, factor)
}

assembly ("memory-safe") {
    let factor := shl(1, gt(x, 0x3))
    x := shr(factor, x)
    result := or(result, factor)
}

if (xInt > int64(uint64(Common.MAX_UINT40))) {
    revert CastingErrors.PRBMath_SD1x18_ToUint40_Overflow(x);
}

using {
    Casting.intoSD59x18,
    Casting.intoUD60x18,
    Casting.intoUint128,
    Casting.intoUint256,
    Casting.intoUint40,
    Casting.unwrap
} for SD1x18 global;

if (xInt > int128(uint128(Common.MAX_UINT40))) {
    revert CastingErrors.PRBMath_SD21x18_ToUint40_Overflow(x);
}

using {
    Casting.intoSD59x18,
    Casting.intoUD60x18,
    Casting.intoUint128,
    Casting.intoUint256,
    Casting.intoUint40,
    Casting.unwrap
} for SD21x18 global;
